+  updateRepoMeta(fields: Record<string, string>): void {
+    const sql = this.requireSql();
+    const allowed = ["description", "visibility", "default_branch"];
+    const sets: string[] = [];
+    const values: string[] = [];
+    for (const [key, val] of Object.entries(fields)) {
+      if (allowed.includes(key)) {
+        sets.push(`${key} = ?`);
+        values.push(val);
